# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.integration.check_with_proof","kind":"function","src_hash":"89b8aa255bd2228e","in":{"base":"ProofTerm"},"out":{"base":"VerificationResult"},"spec":{"lhs":"check_with_proof(pro)","rhs":"verify an explicit proof that source_f \u2261 source_g","over":{"base":"ProofTerm"},"name":"check_with_proof_correct"},"guarantee":"verify an explicit proof that source_f \u2261 source_g","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.integration.check_with_proof_correct","statement":"Path(check_with_proof(x), verify an explicit proof that source_f \u2261 source_g)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"6969831b8aafce2c"}
def check_with_proof(proof: ProofTerm,
                     source_f: str,
                     source_g: str,
                     ctx: Optional[ProofContext] = None) -> VerificationResult:
    """Verify an explicit proof that source_f ≡ source_g.

    Parameters
    ----------
    proof : ProofTerm
        The proof to verify.
    source_f : str
        Source code of function f.
    source_g : str
        Source code of function g.
    ctx : ProofContext, optional
        Additional context (definitions, etc.).

    Returns
    -------
    VerificationResult
        .valid is True iff the proof checks.
    """
    # Compile sources to OTerms
    result_f = compile_to_oterm(source_f)
    result_g = compile_to_oterm(source_g)

    if result_f is None:
        return VerificationResult(False, f'could not compile f: {source_f[:50]}')
    if result_g is None:
        return VerificationResult(False, f'could not compile g: {source_g[:50]}')

    oterm_f, _warnings_f = result_f
    oterm_g, _warnings_g = result_g

    return check_proof(proof, oterm_f, oterm_g, ctx)


