# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.integration.find_proof_file","kind":"function","src_hash":"7f573452ab06ee94","in":{"base":"str"},"out":{"base":"Optional[str]"},"spec":{"lhs":"find_proof_file(sou)","rhs":"find a proof file for a given source file","over":{"base":"str"},"name":"find_proof_file_correct"},"guarantee":"find a proof file for a given source file","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.integration.find_proof_file_correct","statement":"Path(find_proof_file(x), find a proof file for a given source file)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"6ce42c967d603d7c"}
def find_proof_file(source_path: str) -> Optional[str]:
    """Find a proof file for a given source file.

    Looks for:
    1. source.proof.json  (JSON proof)
    2. source.proof.py    (Python proof)
    """
    base = source_path
    if base.endswith('.py'):
        base = base[:-3]

    json_path = f'{base}.proof.json'
    py_path = f'{base}.proof.py'

    if os.path.exists(json_path):
        return json_path
    if os.path.exists(py_path):
        return py_path

    return None


