# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.integration.load_proof_for_pair","kind":"function","src_hash":"97da0cc0b1002dce","in":{"base":"str"},"out":{"base":"Optional[ProofDocument]"},"spec":{"lhs":"load_proof_for_pair(pat)","rhs":"load a proof for a pair of source files","over":{"base":"str"},"name":"load_proof_for_pair_correct"},"guarantee":"load a proof for a pair of source files","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.integration.load_proof_for_pair_correct","statement":"Path(load_proof_for_pair(x), load a proof for a pair of source files)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"656dbef4789d22a3"}
def load_proof_for_pair(path_f: str, path_g: str) -> Optional[ProofDocument]:
    """Load a proof for a pair of source files.

    Searches for proof files associated with either source file.
    """
    # Try proof file for f
    pf = find_proof_file(path_f)
    if pf is not None:
        return _load_proof_file(pf)

    # Try proof file for g
    pg = find_proof_file(path_g)
    if pg is not None:
        return _load_proof_file(pg)

    # Try a combined proof file: f_g.proof.json
    base_f = Path(path_f).stem
    base_g = Path(path_g).stem
    combined = Path(path_f).parent / f'{base_f}_{base_g}.proof.json'
    if combined.exists():
        return _load_proof_file(str(combined))

    return None


