def _load_proof_file(path: str) -> Optional[ProofDocument]:
    """Load a proof from a file (JSON or Python)."""
    if path.endswith('.json'):
        try:
            return load_proof(path)
        except Exception:
            return None

    elif path.endswith('.py'):
        try:
            return _load_python_proof(path)
        except Exception:
            return None

    return None


