# ╚════════════════════════════════════════════════════════════╝
# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.integration._load_python_proof","kind":"function","src_hash":"c19ff83add46e88b","in":{"base":"str"},"out":{"base":"Optional[ProofDocument]"},"spec":{"lhs":"_load_python_proof(pat)","rhs":"load a proof from a python file","over":{"base":"str"},"name":"_load_python_proof_correct"},"guarantee":"load a proof from a python file","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.integration._load_python_proof_correct","statement":"Path(_load_python_proof(x), load a proof from a python file)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"7e05e5dfd4e5b34e"}
def _load_python_proof(path: str) -> Optional[ProofDocument]:
    """Load a proof from a Python file.

    The file must define:
    - PROOF: ProofTerm
    - LHS: OTerm
    - RHS: OTerm
    - Optionally: NAME, DESCRIPTION, STRATEGY
    """
    spec = importlib.util.spec_from_file_location('_proof_module', path)
    if spec is None or spec.loader is None:
        return None

    module = importlib.util.module_from_spec(spec)
    spec.loader.exec_module(module)

    proof = getattr(module, 'PROOF', None)
    lhs = getattr(module, 'LHS', None)
    rhs = getattr(module, 'RHS', None)

    if proof is None or lhs is None or rhs is None:
        return None

    name = getattr(module, 'NAME', Path(path).stem)
    desc = getattr(module, 'DESCRIPTION', '')
    strat = getattr(module, 'STRATEGY', '')

    return ProofDocument(
        name=name, lhs=lhs, rhs=rhs, proof=proof,
        description=desc, strategy=strat,
    )


