# ╚════════════════════════════════════════════════════════════╝
# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.integration.enhanced_check_equivalence","kind":"function","src_hash":"8073a046e0b498ad","in":{"base":"str"},"out":{"base":"Any"},"spec":{"lhs":"enhanced_check_equivalence(sou)","rhs":"drop-in replacement for ``check_equivalence()`` that tries explicit proofs before falling back to heuristics","over":{"base":"str"},"name":"enhanced_check_equivalence_correct"},"guarantee":"drop-in replacement for ``check_equivalence()`` that tries explicit proofs before falling back to heuristics","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.integration.enhanced_check_equivalence_correct","statement":"Path(enhanced_check_equivalence(x), drop-in replacement for ``check_equivalence()`` that tries explicit proofs before falling back to heuristics)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"067f45d3dabfc9fa"}
def enhanced_check_equivalence(source_f: str, source_g: str,
                               timeout_ms: int = 5000,
                               proof: Optional[ProofTerm] = None,
                               proof_file: Optional[str] = None) -> Any:
    """Drop-in replacement for ``check_equivalence()`` that tries
    explicit proofs before falling back to heuristics.

    Strategy ordering:
    0.  Explicit proof verification (if proof/proof_file given)
    0.5 Proof file discovery (look for *.proof.json / *.proof.py)
    1+  Original CCTT pipeline (denotational, Z3, Čech, bounded test)

    Parameters
    ----------
    source_f, source_g : str
        Source code of the two functions.
    timeout_ms : int
        Timeout for heuristic fallback.
    proof : ProofTerm, optional
        Explicit proof term.
    proof_file : str, optional
        Path to a proof file.

    Returns
    -------
    Result (from cctt.checker)
    """
    from cctt.checker import Result, check_equivalence

    # ── Strategy 0: Explicit proof ──
    if proof is not None:
        vr = check_with_proof(proof, source_f, source_g)
        if vr.valid:
            return Result(
                equivalent=True,
                explanation=f'proof verified: {vr.reason}',
                h0=1, h1=0, confidence=1.0,
            )

    # ── Strategy 0.5: Proof file ──
    if proof_file is not None:
        doc = _load_proof_file(proof_file)
        if doc is not None:
            vr = check_with_proof(doc.proof, source_f, source_g)
            if vr.valid:
                return Result(
                    equivalent=True,
                    explanation=f'proof file verified: {doc.name}',
                    h0=1, h1=0, confidence=1.0,
                )

    # ── Strategy 1+: Original pipeline ──
    return check_equivalence(source_f, source_g, timeout_ms)


