# Global proof registry: (source_f_hash, source_g_hash) → ProofTerm
_PROOF_REGISTRY: Dict[Tuple[str, str], ProofTerm] = {}


# ╔══ CCTT ══════════════════════════════════════════════════╗
# ║ Path(register_proof(sou), register a proof for a pair of programs) over str ║
