# ╠════════════════════════════════════════════════════════════╣
# ║ 🟢 KERNEL | library_axiom | Compiled: ✓ | f8e928dcce2c72bf  ║
# ╚════════════════════════════════════════════════════════════╝
# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.integration.register_proof","kind":"function","src_hash":"653406fd39e260af","in":{"base":"str"},"out":{"base":"None"},"spec":{"lhs":"register_proof(sou)","rhs":"register a proof for a pair of programs","over":{"base":"str"},"name":"register_proof_correct"},"guarantee":"register a proof for a pair of programs","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.integration.register_proof_correct","statement":"Path(register_proof(x), register a proof for a pair of programs)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"f8e928dcce2c72bf"}
def register_proof(source_f: str, source_g: str,
                   proof: ProofTerm) -> None:
    """Register a proof for a pair of programs.

    The proof will be used by enhanced_check_equivalence when
    checking these programs.
    """
    import hashlib
    hf = hashlib.md5(source_f.encode()).hexdigest()
    hg = hashlib.md5(source_g.encode()).hexdigest()
    _PROOF_REGISTRY[(hf, hg)] = proof
    _PROOF_REGISTRY[(hg, hf)] = proof


